/**
 * feats-list.js
 * Database Talenti PF1 — usati per autocompletamento nel tab Talenti.
 * Quando l'utente seleziona un talento, tipo, prerequisiti e beneficio vengono pre-compilati.
 *
 * window.PF1_FEATS_DB — array globale di talenti
 * Ogni voce: { name, type, prerequisites, benefit, source }
 *
 * type: 'Generali' | 'Combattimento' | 'Metamagia' | 'Critico' | 'Stile'
 *       | 'Incanalare Energia' | 'Squadra' | 'Eroici' | 'Trama' | 'Creazione Oggetti'
 *
 * nameEN: nome inglese (facoltativo) — consente di cercare per nome EN nel modal Talenti
 *
 * source abbreviazioni:
 *   MdG = Manuale di Gioco (Core Rulebook)
 *   GdG = Guida del Giocatore (APG)
 *   GC  = Guida al Combattimento (Ultimate Combat)
 *   GM  = Guida alla Magia (Ultimate Magic)
 *   GCl = Guida alle Classi (Advanced Class Guide)
 *   GR  = Guida alle Razze (Advanced Race Guide)
 *   UI  = Ultimate Intrigue
 *   AO  = Avventure Occulte (Occult Adventures)
 *   AE  = Avventure dell'Orrore (Horror Adventures)
 *   GCa = Guida alla Campagna (Campaign Setting)
 *   VC  = Villain Codex
 *   AG  = Adventurer's Guide
 *   AM  = Avventure Mitiche (Mythic Adventures)
 *   UW  = Ultimate Wilderness
 *
 * NOTA: Database parziale — priorità Manuale di Gioco, poi supplementi comuni.
 * Dati verificati da: https://golarion.altervista.org/wiki/Database_Talenti
 */

